def validate_uve_arc(program: dict) -> dict:
    """Validate UVE arc completeness"""
    required_phases = ["breakthrough", "milestone", "miracle", "transformation"]
    issues = []

    uve_arc = program.get("uve_arc", {})
    for phase in required_phases:
        if phase not in uve_arc:
            issues.append(f"Missing UVE phase: {phase}")
        elif not uve_arc[phase].get("proof"):
            issues.append(f"UVE phase '{phase}' missing proof metric")

    return {
        "passed": len(issues) == 0,
        "phases_defined": len([p for p in required_phases if p in uve_arc]),
        "issues": issues
    }

def validate_whole_solution(program: dict) -> dict:
    """Validate whole solution layers"""
    required_layers = ["physical", "digital", "social", "ai"]
    issues = []

    layers = program.get("layers", {})
    for layer in required_layers:
        if layer not in layers:
            issues.append(f"Missing layer: {layer}")
        elif layers[layer].get("na") and not layers[layer].get("mitigation"):
            issues.append(f"Layer '{layer}' marked N/A but no mitigation provided")

    return {
        "passed": len(issues) == 0,
        "layers_addressed": len([l for l in required_layers if l in layers]),
        "issues": issues
    }

def validate_retention_hooks(modules: list) -> dict:
    """Validate retention hooks in each module"""
    required_hooks = ["ai_checkin", "community", "completion_trigger"]
    issues = []

    for i, module in enumerate(modules):
        for hook in required_hooks:
            if hook not in module.get("retention", {}):
                issues.append(f"Module {i+1} missing retention hook: {hook}")

    return {
        "passed": len(issues) == 0,
        "modules_checked": len(modules),
        "issues": issues
    }
